package genxsolution.vms.vmsbackend.maintenance_management.breakdown_record.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.breakdown_record.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.breakdown_record.service.BreakdownRecordService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/breakdown-records") public class BreakdownRecordController { private final BreakdownRecordService service; public BreakdownRecordController(BreakdownRecordService service){this.service=service;} @GetMapping public List<BreakdownRecordResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public BreakdownRecordResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public BreakdownRecordResponse create(@RequestBody BreakdownRecordUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public BreakdownRecordResponse update(@PathVariable UUID id,@RequestBody BreakdownRecordUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
